//! DinoV2 ViT-B/14 (reg) pathology encoder — sovereign forward for the monster-mesh
//! "Microscope" embedding endpoint. This is OUR trained checkpoint (the giant-teacher
//! run, best mean_probe_score 0.6117), exported to .knot by packages/nanopath/export_knot.py.
//!
//! Arch (from packages/nanopath/model.py DinoV2ViT, dinov2_vitb14_reg):
//!   - 224x224 RGB -> 14px conv patch embed -> 16x16 = 256 patch tokens
//!   - token sequence: [CLS, REG0..REG3, PATCH0..PATCH255] = 261 tokens
//!   - positional embedding is BAKED at export (bicubic+antialias 37x37->16x16) into
//!     `pos_embed_baked` [257,768] = [CLS_pos, patch0_pos..patch255_pos]; registers get NO pos.
//!     pos is added to [CLS, patches] BEFORE the registers are spliced in (matching _prepare_tokens).
//!   - 12 pre-norm blocks: norm1 -> MHA -> LayerScale(ls1) -> +res ; norm2 -> GELU-MLP -> LayerScale(ls2) -> +res
//!   - final LayerNorm (eps 1e-6) over all tokens
//!   - readout: CLS = x[0] after final norm (raw, NOT L2-normalized here); rk_fusion =
//!     final-norm'd CLS at blocks {4,6,8,11} concatenated -> 3072-d (the strongest readout).
//!
//! Runs CPU-only on the math.rs kernels (no candle); ~0.6 GFLOP/tile, ms-scale.

use std::collections::HashMap;
use std::sync::Arc;

use crate::loader::WeightBackend;
use crate::math::{accumulate_weighted, dot_product, gelu_inplace, layer_norm, mat_vec_f32, softmax};

#[derive(Debug, Clone)]
pub struct DinoV2VitConfig {
    pub hidden: usize,       // 768
    pub depth: usize,        // 12
    pub heads: usize,        // 12
    pub head_dim: usize,     // 64
    pub intermediate: usize, // 3072
    pub patch: usize,        // 14
    pub grid: usize,         // 16  (224/14)
    pub registers: usize,    // 4
    pub eps: f32,            // 1e-6
}

impl Default for DinoV2VitConfig {
    fn default() -> Self {
        Self { hidden: 768, depth: 12, heads: 12, head_dim: 64, intermediate: 3072,
               patch: 14, grid: 16, registers: 4, eps: 1e-6 }
    }
}

impl DinoV2VitConfig {
    pub fn n_patches(&self) -> usize { self.grid * self.grid } // 256
    pub fn n_tokens(&self) -> usize { 1 + self.registers + self.n_patches() } // 261
}

/// Which embedding to return.
pub enum Readout {
    /// 768-d final-norm'd CLS token.
    Cls,
    /// concat of final-norm'd CLS at the given block depths (e.g. [4,6,8,11] -> 3072-d).
    RkFusion(Vec<usize>),
}

pub struct DinoV2ViT {
    pub config: DinoV2VitConfig,
    w: HashMap<String, Vec<f32>>, // all weights prefetched + dequantized to f32
}

impl DinoV2ViT {
    /// Prefetch + dequantize every named tensor once (ViT-B is small). Fails fast on a
    /// missing/instructed-wrong tensor so a bad .knot is caught at load, not mid-request.
    pub fn new(config: DinoV2VitConfig, backend: Arc<dyn WeightBackend>) -> Result<Self, String> {
        let mut names = vec![
            "patch_embed_w".to_string(), "patch_embed_b".to_string(),
            "cls_token".to_string(), "register_tokens".to_string(),
            "pos_embed_baked".to_string(), "norm_w".to_string(), "norm_b".to_string(),
        ];
        for i in 0..config.depth {
            for s in ["norm1_w","norm1_b","qkv_w","qkv_b","proj_w","proj_b","ls1",
                      "norm2_w","norm2_b","fc1_w","fc1_b","fc2_w","fc2_b","ls2"] {
                names.push(format!("blk_{i}_{s}"));
            }
        }
        let mut w = HashMap::with_capacity(names.len());
        for name in names {
            let v = fetch_f32(backend.as_ref(), &name)?;
            w.insert(name, v);
        }
        Ok(Self { config, w })
    }

    #[inline]
    fn g(&self, name: &str) -> &[f32] {
        self.w.get(name).map(|v| v.as_slice()).unwrap_or(&[])
    }

    /// forward: `pixels` is normalized CHW f32, length 3*224*224 (R,G,B planes; already
    /// (x/255 - mean)/std). Returns the requested embedding (NOT L2-normalized; the TS
    /// sieve L2-normalizes, matching the Python probe).
    pub fn forward(&self, pixels: &[f32], readout: &Readout) -> Result<Vec<f32>, String> {
        let c = &self.config;
        let h = c.hidden;
        let img = c.grid * c.patch; // 224
        let expect = 3 * img * img;
        if pixels.len() != expect {
            return Err(format!("forward: expected {expect} CHW f32 (3x{img}x{img}), got {}", pixels.len()));
        }
        let n_patches = c.n_patches();
        let n = c.n_tokens();
        let patch_dim = 3 * c.patch * c.patch; // 588

        // ---- token buffer x[n, h] in order [CLS, REG0..3, PATCH0..255] -------------------
        let mut x = vec![0f32; n * h];
        let pos = self.g("pos_embed_baked"); // [257, h] = [cls_pos, patch0..255_pos]
        let cls = self.g("cls_token");        // [h]
        let regs = self.g("register_tokens"); // [registers*h]
        let pe_w = self.g("patch_embed_w");   // [h, patch_dim]
        let pe_b = self.g("patch_embed_b");   // [h]

        // CLS (index 0): cls_token + pos[0]
        for i in 0..h { x[i] = cls[i] + pos[i]; }
        // registers (indices 1..1+registers): raw token, NO pos
        for r in 0..c.registers {
            let dst = &mut x[(1 + r) * h..(2 + r) * h];
            dst.copy_from_slice(&regs[r * h..(r + 1) * h]);
        }
        // patches (indices 1+registers .. n): conv-as-matmul + bias + pos[1+i]
        let mut patch = vec![0f32; patch_dim];
        for p in 0..n_patches {
            let gy = p / c.grid;
            let gx = p % c.grid;
            // gather patch in (channel, kh, kw) order to match torch conv weight [out,in,kh,kw].reshape
            let mut k = 0usize;
            for ch in 0..3 {
                let base = ch * img * img;
                for kh in 0..c.patch {
                    let row = base + (gy * c.patch + kh) * img + gx * c.patch;
                    for kw in 0..c.patch {
                        patch[k] = pixels[row + kw];
                        k += 1;
                    }
                }
            }
            let tok = 1 + c.registers + p;
            let dst = &mut x[tok * h..(tok + 1) * h];
            mat_vec_f32(dst, &patch, pe_w, h, patch_dim); // dst = pe_w @ patch
            let ppos = &pos[(1 + p) * h..(2 + p) * h];
            for i in 0..h { dst[i] += pe_b[i] + ppos[i]; }
        }

        // ---- 12 transformer blocks ------------------------------------------------------
        let rk_depths: Vec<usize> = match readout {
            Readout::RkFusion(d) => d.clone(),
            Readout::Cls => Vec::new(),
        };
        let mut rk_parts: HashMap<usize, Vec<f32>> = HashMap::new();

        for l in 0..c.depth {
            self.block(&mut x, l, n)?;
            if rk_depths.contains(&l) {
                rk_parts.insert(l, self.final_norm_cls(&x)); // final-norm'd CLS at this depth
            }
        }

        match readout {
            Readout::Cls => Ok(self.final_norm_cls(&x)),
            Readout::RkFusion(depths) => {
                let mut sorted = depths.clone();
                sorted.sort_unstable();
                let last = c.depth - 1;
                if !sorted.contains(&last) {
                    sorted.push(last);
                    rk_parts.insert(last, self.final_norm_cls(&x));
                }
                let mut out = Vec::with_capacity(sorted.len() * h);
                for d in sorted {
                    let part = rk_parts.get(&d)
                        .ok_or_else(|| format!("rk_fusion depth {d} out of range (depth={})", c.depth))?;
                    out.extend_from_slice(part);
                }
                Ok(out)
            }
        }
    }

    /// final LayerNorm applied to the CLS token only -> [h].
    fn final_norm_cls(&self, x: &[f32]) -> Vec<f32> {
        let h = self.config.hidden;
        let mut out = vec![0f32; h];
        layer_norm(&mut out, &x[0..h], self.g("norm_w"), self.g("norm_b"), self.config.eps);
        out
    }

    /// One pre-norm transformer block, in place on x[n, h].
    fn block(&self, x: &mut [f32], l: usize, n: usize) -> Result<(), String> {
        let c = &self.config;
        let h = c.hidden;
        let hd = c.head_dim;
        let scale = 1.0f32 / (hd as f32).sqrt();

        // ---- attention branch: y = ls1 * proj(MHA(norm1(x))) ; x += y ----
        // 1. norm1 over each token
        let mut xn = vec![0f32; n * h];
        let n1w = self.g(&format!("blk_{l}_norm1_w"));
        let n1b = self.g(&format!("blk_{l}_norm1_b"));
        for t in 0..n {
            layer_norm(&mut xn[t * h..(t + 1) * h], &x[t * h..(t + 1) * h], n1w, n1b, c.eps);
        }
        // 2. qkv projection per token -> q,k,v stacked [n, 3h]
        let qkv_w = self.g(&format!("blk_{l}_qkv_w")); // [3h, h]
        let qkv_b = self.g(&format!("blk_{l}_qkv_b")); // [3h]
        let mut qkv = vec![0f32; n * 3 * h];
        for t in 0..n {
            let dst = &mut qkv[t * 3 * h..(t + 1) * 3 * h];
            mat_vec_f32(dst, &xn[t * h..(t + 1) * h], qkv_w, 3 * h, h);
            for i in 0..3 * h { dst[i] += qkv_b[i]; }
        }
        // helper closures into qkv: q at [.. h], k at [h..2h], v at [2h..3h]
        let head_off = |t: usize, part: usize, head: usize| t * 3 * h + part * h + head * hd;
        // 3. attention -> attn_out [n, h]
        let mut attn = vec![0f32; n * h];
        let mut scores = vec![0f32; n];
        for i in 0..n {
            for head in 0..c.heads {
                let q = &qkv[head_off(i, 0, head)..head_off(i, 0, head) + hd];
                for j in 0..n {
                    let k = &qkv[head_off(j, 1, head)..head_off(j, 1, head) + hd];
                    scores[j] = dot_product(q, k) * scale;
                }
                softmax(&mut scores[..n]);
                let out = &mut attn[i * h + head * hd..i * h + head * hd + hd];
                for j in 0..n {
                    let v = &qkv[head_off(j, 2, head)..head_off(j, 2, head) + hd];
                    accumulate_weighted(out, v, scores[j]);
                }
            }
        }
        // 4. proj + ls1 + residual
        let pw = self.g(&format!("blk_{l}_proj_w")); // [h,h]
        let pb = self.g(&format!("blk_{l}_proj_b"));
        let ls1 = self.g(&format!("blk_{l}_ls1"));   // [h]
        let mut tmp = vec![0f32; h];
        for t in 0..n {
            mat_vec_f32(&mut tmp, &attn[t * h..(t + 1) * h], pw, h, h);
            for i in 0..h { x[t * h + i] += (tmp[i] + pb[i]) * ls1[i]; }
        }

        // ---- MLP branch: y = ls2 * fc2(gelu(fc1(norm2(x)))) ; x += y ----
        let n2w = self.g(&format!("blk_{l}_norm2_w"));
        let n2b = self.g(&format!("blk_{l}_norm2_b"));
        let fc1 = self.g(&format!("blk_{l}_fc1_w")); // [inter, h]
        let fc1b = self.g(&format!("blk_{l}_fc1_b"));
        let fc2 = self.g(&format!("blk_{l}_fc2_w")); // [h, inter]
        let fc2b = self.g(&format!("blk_{l}_fc2_b"));
        let ls2 = self.g(&format!("blk_{l}_ls2"));
        let mut xn2 = vec![0f32; h];
        let mut hid = vec![0f32; c.intermediate];
        let mut out = vec![0f32; h];
        for t in 0..n {
            layer_norm(&mut xn2, &x[t * h..(t + 1) * h], n2w, n2b, c.eps);
            mat_vec_f32(&mut hid, &xn2, fc1, c.intermediate, h);
            for i in 0..c.intermediate { hid[i] += fc1b[i]; }
            gelu_inplace(&mut hid);
            mat_vec_f32(&mut out, &hid, fc2, h, c.intermediate);
            for i in 0..h { x[t * h + i] += (out[i] + fc2b[i]) * ls2[i]; }
        }
        Ok(())
    }
}

/// Fetch a tensor as f32, dequantizing per its declared qtype (mirrors model_qwen2vl_vit.rs).
fn fetch_f32(backend: &dyn WeightBackend, name: &str) -> Result<Vec<f32>, String> {
    let bytes = backend.fetch_tensor(name).map_err(|e| format!("{name}: {e}"))?;
    let qtype = backend
        .tensor_info(name)
        .map(|ti| ti.tensor_type.to_ascii_lowercase())
        .unwrap_or_else(|| "f32".to_string());
    match qtype.as_str() {
        "q8_0" => {
            let n_elems = (bytes.len() / 34) * 32;
            let mut out = vec![0f32; n_elems];
            crate::math::dequantize_q8_0_row(&mut out, &bytes, 0, n_elems);
            Ok(out)
        }
        "f32" | "fp32" => {
            if bytes.len() % 4 != 0 {
                return Err(format!("fetch_f32 {name}: f32 len {} not /4", bytes.len()));
            }
            Ok(bytes.chunks_exact(4).map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]])).collect())
        }
        other => Err(format!("fetch_f32 {name}: unsupported qtype '{other}' (expected f32 or Q8_0)")),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    #[test]
    fn config_dims() {
        let c = DinoV2VitConfig::default();
        assert_eq!(c.hidden, 768);
        assert_eq!(c.depth, 12);
        assert_eq!(c.n_patches(), 256);
        assert_eq!(c.n_tokens(), 261); // CLS + 4 regs + 256 patches
        assert_eq!(c.heads * c.head_dim, c.hidden);
    }
}
